import { AgentRun, WorkflowStep } from 'mastra';

const detectToolLoop = (steps: WorkflowStep[]): boolean => {
  const toolCalls = steps
    .filter(step => step.type === 'tool')
    .map(step => `${step.toolName}:${JSON.stringify(step.input)}`);

  const sequences = [];
  for (let i = 0; i < toolCalls.length - 3; i++) {
    sequences.push(toolCalls.slice(i, i + 4).join('->'));
  }

  const sequenceCounts = sequences.reduce((acc, seq) => {
    acc[seq] = (acc[seq] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  return Object.values(sequenceCounts).some(count => count >= 3);
};

// Usage in Mastra agent runner
const monitorLoop = (agentRun: AgentRun) => {
  if (detectToolLoop(agentRun.steps)) {
    console.warn('🔄 TOOL LOOP DETECTED:', agentRun.id);
    return true;
  }
  return false;
};

import { MemoryContext } from 'mastra';

const detectMemoryLoop = (memory: MemoryContext, currentStep: WorkflowStep): boolean => {
  const toolArtifacts = [
    'tool_result',
    'search_results',
    'api_response',
    'parsed_data'
  ];

  const memoryContent = JSON.stringify(memory);
  const recentToolCalls = memoryContent.match(/tool_name\s*:\s*["']([^"']+)["']/g) || [];

  // Check if memory contains >3 identical tool calls
  const toolCounts = recentToolCalls.reduce((acc, match) => {
    const toolName = match.match(/["']([^"']+)["']/)?.[1];
    if (toolName) acc[toolName] = (acc[toolName] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  return Object.values(toolCounts).some(count => count > 3);
};

import { AgentSession } from 'mastra';

const trackTokenLoops = (session: AgentSession): { looping: boolean; pattern: string } => {
  const { steps, totalTokens } = session;
  const toolSteps = steps.filter(s => s.type === 'tool');

  if (toolSteps.length > 10 && totalTokens > session.maxTokens * 0.8) {
    const lastTools = toolSteps.slice(-5).map(s => s.toolName).join(' → ');
    return {
      looping: true,
      pattern: `High token usage (${totalTokens}) with repeating tools: ${lastTools}`
    };
  }

  return { looping: false, pattern: '' };
};

