import { WorkflowMiddleware } from 'mastra';

const loopPreventionMiddleware: WorkflowMiddleware = async (context, next) => {
  const { step, memory } = context;

  if (step.type === 'tool') {
    // Validate tool output schema
    const outputValid = validateToolOutput(step.output, step.toolName);

    if (!outputValid) {
      // Break loop with error state
      context.memory.set('LOOP_BROKEN', {
        reason: 'Invalid tool output',
        tool: step.toolName,
        output: step.output
      });
      return { status: 'error', message: 'Tool loop prevented' };
    }
  }

  // Check for repeating tool patterns
  const recentTools = memory.get('recent_tools') || [];
  recentTools.push(step.toolName);

  if (recentTools.length > 5) {
    recentTools.shift();
    if (recentTools.every(t => t === recentTools[0])) {
      throw new Error('Tool loop detected and blocked');
    }
  }

  memory.set('recent_tools', recentTools);
  return next();
};

const validateToolOutput = (output: any, toolName: string): boolean => {
  // Tool-specific validation
  switch (toolName) {
    case 'searchTool':
      return !!output.results && output.results.length > 0;
    case 'parseTool':
      return !!output.data && typeof output.data === 'object';
    default:
      return true;
  }
};

import { MemoryManager } from 'mastra';

const cleanLoopMemory = (memoryManager: MemoryManager): MemoryManager => {
  const context = memoryManager.getContext();
  const cleaned = Object.entries(context).reduce((acc, [key, value]) => {
    // Remove tool loop indicators
    if (/\/tool_result|api_response|search_results/.test(key)) {
      const toolAge = (Date.now() - (value as any).timestamp) / 1000 / 60;
      if (toolAge > 5) { // 5 min TTL
        console.log(`🧹 Cleared stale tool memory: ${key}`);
        return acc;
      }
    }
    acc[key] = value;
    return acc;
  }, {} as any);

  memoryManager.setContext(cleaned);
  return memoryManager;
};

// Apply before each agent step
const agentExecutor = async (agentId: string, input: any) => {
  const memory = await memoryManager.get(agentId);
  const cleanedMemory = cleanLoopMemory(memory);
  // Continue with cleaned memory
};

import { AgentExecutor } from 'mastra';

const safeAgentExecutor: AgentExecutor = {
  maxIterations: 15,
  async execute(agentId: string, input: any) {
    let iteration = 0;
    const toolHistory: string[] = [];

    while (iteration < this.maxIterations) {
      const result = await this.agent.run(input);

      if (result.type === 'tool') {
        const toolSig = `${result.toolName}:${JSON.stringify(result.input).slice(0, 50)}`;
        toolHistory.push(toolSig);

        // Detect 4+ identical tool calls
        if (toolHistory.length >= 4 && 
            toolHistory.slice(-4).every(sig => sig === toolSig)) {
          throw new Error(`Tool loop detected: ${toolSig} x4`);
        }
      }

      iteration++;
      if (result.complete) break;
    }
  }
};

