import { Vex } from '@vex_dev/sdk';
import { MastraAgent, WorkflowStep } from 'mastra';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!
});

// Mastra middleware integration
const mastraLoopGuard = async (agent: MastraAgent, steps: WorkflowStep[]) => {
  // Send execution trace to Vex
  const trace = await vex.trace({
    name: 'mastra-tool-loop-check',
    input: { agentId: agent.id, steps },
    metadata: {
      framework: 'mastra',
      totalTokens: agent.session.totalTokens,
      toolCalls: steps.filter(s => s.type === 'tool').length
    }
  });

  if (trace.hasIssue('tool-loop')) {
    // Vex auto-remediates
    await vex.remediate({
      traceId: trace.id,
      fix: 'clear_memory',
      actions: [
        'terminate_workflow',
        'reset_tool_history',
        'inject_progress_prompt'
      ]
    });

    console.log('✅ Vex blocked tool loop:', trace.issue);
    return { blocked: true };
  }

  return { safe: true };
};

// Install in Mastra agent pipeline
agent.useMiddleware(mastraLoopGuard);
